INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('f075843a-b03a-57f0-8925-e56f3aa6f2ad', '40c0d09d-c03c-4dc3-80ee-623ce1d3a08a', 'It takes time and patience to ___ a new language fluently.', '要流利地習得一種新語言需要時間與耐心。', 'acquire', 'donate', 'refuse', 'predict', '字首 ac- (趨向) + 字根 quire (尋求) → 趨向於尋求某物 → 取得、獲得。', 'ac (去) + quire (尋找) → 去尋找並拿到手 → 取得。', '2026-07-06 17:17:27', '2026-07-06 17:17:27'),
('f78a223f-8fcb-59e4-99ae-4a6110c0f16d', 'c0d86ce2-1e31-4b74-8cc8-69230656dcc0', 'The courageous ___ commanded the entire naval fleet during the intense sea battle.', '這位勇敢的艦隊司令在激烈的海戰中指揮著整個海軍艦隊。', 'admiral', 'professor', 'lawyer', 'musician', '詞源來自阿拉伯語 amīr，意指指揮官，後來演變為海軍的高級將領。', '聯想 admire (欽佩) → admiral (上將)：大家都非常欽佩這位指揮艦隊的上將。', '2026-07-06 17:52:26', '2026-07-06 17:52:26'),
('38868f4c-d2e4-503e-96e3-72563d9b2089', 'f517f55b-9c3c-43c6-bc46-314312fa5f41', 'Please write your ___ on this form.', '請在這張表格上寫下你的年齡。', 'age', 'name', 'color', 'size', 'age 作為名詞，表示年齡。', 'age 讀音像 愛及，愛及長大就是年齡。', '2026-07-06 13:28:19', '2026-07-06 13:28:19'),
('9a4a4b04-13e9-5b60-b3c0-cba92a5cdab9', 'bfa4c7a5-76d3-436c-885d-ed91ea297b32', 'The travel ___ helped us book all our flights and hotels for the summer vacation.', '這家旅行社幫助我們預訂了暑假所有的機票和飯店。', 'agency', 'library', 'museum', 'stadium', 'agent (代理人) + -cy (名詞字尾，表示性質或機構) → agency (代理機構、仲介)', '想像一個 agent (代理人) 在工作的組織，加上 -cy 就變成了 agency (代理處)。', '2026-07-06 18:53:54', '2026-07-06 18:53:54'),
('9947582c-202a-5b17-9375-5281013dccc9', 'c2ab26ec-13c3-4c73-a8ed-ac40bb801088', 'She ate ___ of the cookies, so there are none left.', '她吃了所有的餅乾，所以現在一個都不剩了。', 'all', 'some', 'many', 'few', 'All 表示「全部」，在此作為代名詞使用。', 'All 就像一個大籃子，裝滿了所有東西。', '2026-07-06 13:45:09', '2026-07-06 13:45:09'),
('1ef29d62-9867-573d-8481-326cc1cca041', '28c50501-171d-48f7-95ca-d0690e2c6556', 'The French ___ arrived in Taipei yesterday to discuss new trade agreements between the two nations.', '法國大使昨天抵達台北，討論兩國之間的新貿易協定。', 'ambassador', 'passenger', 'architect', 'scientist', 'amb- 代表兩邊或周圍，-ador 代表做某事的人，合起來就是兩國之間往返的人。', '想像一個在兩國之間(amb)走來走去(ass)的人(ador)。', '2026-07-06 20:37:52', '2026-07-06 20:37:52'),
('9a526251-2ed3-56f4-839a-1bd115be09fd', '921f0ee2-c07b-4d2e-a7f3-f505d3b44513', 'If there is ___ left in the box, please let me know.', '如果盒子裡還有任何東西，請告訴我。', 'any', 'some', 'all', 'much', 'any 在 if 引導的條件句中作為代名詞，表示「任何東西」', 'If + any = 只要有任何一個 → 條件句常用 any', '2026-07-06 22:19:21', '2026-07-06 22:19:21'),
('96d8423b-ee47-508b-b060-3a00fb85a82d', 'a811502c-2534-4f9e-85cf-e0315a21a08d', 'Most experts estimate that the repair work will cost ___ five thousand dollars.', '大多數專家估計，修理工作將花費大約五千美元。', 'around', 'during', 'since', 'despite', 'around 在此作為介係詞，用來表示數量的「大約、大概」。', '數字前後繞著走，表示一個不精確的大致範圍。', '2026-07-07 00:03:45', '2026-07-07 00:03:45'),
('34a28281-5063-5d62-a0ae-50faaca07c99', '59f839cf-829e-48c6-a458-d91e28f76337', 'Please put all the red apples into the large ___.', '請把所有的紅蘋果都放進那個大籃子裡。', 'basket', 'box', 'spoon', 'chair', 'basket 為名詞，指用藤條或竹子編織而成的容器。', '想像一個裝滿水果的編織籃子 → basket', '2026-07-07 02:31:45', '2026-07-07 02:31:45'),
('a033bccc-3db3-5fd4-99fb-c854320ff55d', 'bb56a3e8-f551-4c89-b587-8f5e9bae4654', 'I stayed at home ___ it was raining heavily.', '我待在家裡，因為雨下得很大。', 'because', 'although', 'if', 'but', 'because 由 be + cause (造成) 組成，字面意思是「造成...的原因」。', '看到 because 就聯想到「因為」，用來解釋後面的原因。', '2026-07-07 02:51:02', '2026-07-07 02:51:02'),
('3c1eadb9-19af-52fd-b4cc-6fc9e3ebc805', 'd667c061-2c22-45e8-9076-8f9dc69d5155', 'A caterpillar will ___ a beautiful butterfly.', '毛毛蟲會變成一隻美麗的蝴蝶。', 'become', 'feel', 'look', 'stay', 'be (在/是) + come (來) → 來到某種狀態 → 變成', '走到 (come) 到某個狀態 (be) → 變成', '2026-07-07 02:56:59', '2026-07-07 02:56:59'),
('8a609822-b5d1-54ff-9701-fc2cbb57ab81', 'f1b5cab1-657a-4768-9011-0202a116ab5f', 'The library is in this ___.', '圖書館在這個街區。', 'block', 'forest', 'ocean', 'mountain', 'block 為單字本身，當名詞時表示「街區」。', '把城市分成一塊一塊的區域 → 每一塊就是一個街區。', '2026-07-07 04:03:44', '2026-07-07 04:03:44'),
('47dd072b-ea9a-50c0-b75a-5f8e39036d55', '0e1e35bd-5aa4-4e4f-8bc2-4ac5a6d7416c', 'It is very ___ to cry just because you lost a game.', '只因為輸了比賽就哭，是非常幼稚的行為。', 'childish', 'hungry', 'famous', 'careful', 'child (小孩) + -ish (具有...特質的) → 像小孩一樣的 → 幼稚的。', '記住 child 是「小孩」，-ish 是「像...一樣的」後綴。childish 就是「像小孩一樣的」，通常用來形容行為很幼稚。', '2026-07-07 03:44:37', '2026-07-07 03:44:37'),
('6bf7cd06-c825-500b-a350-878e86e2bfc5', '43e71354-7db1-442e-b861-19feb8e2188e', 'She gave her daughter a cute ___ for her birthday.', '她送了她女兒一個可愛的洋娃娃作為生日禮物。', 'doll', 'book', 'ring', 'bag', 'doll 為單一單字，無字根。', 'doll 想像一個小娃娃 (doll) 在跳舞。', '2026-07-07 05:04:49', '2026-07-07 05:04:49'),
('4f6292a1-f777-5377-9f62-f33fa21fa5fd', '08d7bf36-48f0-4253-a22b-7357bfa6e2a1', 'The smell ___ fresh bread filled the room.', '新鮮麵包的香味充滿了整個房間。', 'of', 'in', 'at', 'on', '介係詞，用來表示性質或內容', 'the smell of... 表示「...的香味」', '2026-07-05 10:16:03', '2026-07-05 10:16:03');
